SELECT id, interface_id, config_name, wsdl_url, service_url, namespace, operation_name, port_name, soap_version, soap_action, mtom_enabled, ws_security_type, ws_username, ws_password, ws_password_type, keystore_path, keystore_password, timeout_ms, request_template, response_path, wsdl_cached_at, wsdl_cache, is_active, created_at, updated_at FROM eai_soap_config
AND interface_id = #{interfaceId}
ORDER BY id
